     9	int
    10	main(int argc, char* argv[])
    11	{
    12	  if (argc != 3) {
    13	    std::cout << "Usage: " << argv[0] << " <input> <output>\n";
    14	    return -1;
    15	  }
    16	
    17	  auto inFileOrErr = llvm::MemoryBuffer::getFile(argv[1]);
    18	  if (auto err = inFileOrErr.getError()) {
    19	    std::cout << "Error: unable to open input file: " << argv[1] << '\n';
    20	    return -2;
    21	  }
    22	  auto inFile = std::move(inFileOrErr.get());
    23	  std::error_code ec;
    24	  llvm::StringRef outPath(argv[2]);
    25	  llvm::raw_fd_ostream outFile(outPath, ec);
    26	  if (ec) {
    27	    std::cout << "Error: unable to open output file: " << argv[2] << '\n';
    28	    return -3;
    29	  }
    30	
    31	  auto json = llvm::json::parse(inFile->getBuffer());
    32	  if (!json) {
    33	    std::cout << "Error: unable to parse input file: " << argv[1] << '\n';
    34	    return 1;
    35	  }
    36	
    37	  // 读取 JSON，转换为 ASG
    38	  Obj::Mgr mgr;
    39	  Json2Asg json2asg(mgr);
    40	  auto asg = json2asg(json.get());
    41	  mgr.mRoot = asg;
    42	  mgr.gc();
    43	
    44	  // 从 ASG 发射到 LLVM IR
    45	  llvm::LLVMContext ctx;
    46	  EmitIR emitIR(mgr, ctx);
    47	  auto& mod = emitIR(asg);
    48	  mgr.gc();
    49	
    50	  // 先把 LLVM IR 写出到文件里，再检查合不合法
    51	  mod.print(outFile, nullptr, false, true);
    52	  if (llvm::verifyModule(mod, &llvm::outs()))
    53	    return 3;
    54	}
